#pragma OPENCL EXTENSION cl_khr_fp64 : enable

kernel void hotspotOpt1(cl_mem p, cl_mem tIn, cl_mem tOut, float sdc,
        int nx, int ny, int nz,
        float ce, float cw, 
        float cn, float cs,
        float ct, float cb, 
        float cc) 
{
    float amb_temp = 80.0;

    int i = get_local_id(0) + get_group_id(0) * get_local_size(0);  
    int j = get_local_id(1) + get_group_id(1) * get_local_size(1);

    int c = i + j * nx;
    int xy = nx * ny;

    int W = (i == 0)        ? c : c - 1;
    int E = (i == nx-1)     ? c : c + 1;
    int N = (j == 0)        ? c : c - nx;
    int S = (j == ny-1)     ? c : c + nx;

    float temp1, temp2, temp3;
    temp1 = temp2 = ((const float*)tIn)[c];
    temp3 = ((const float*)tIn)[c+xy];
    ((float*)tOut)[c] = cc * temp2 + cw * ((const float*)tIn)[W] + ce * ((const float*)tIn)[E] + cs * ((const float*)tIn)[S]
        + cn * ((const float*)tIn)[N] + cb * temp1 + ct * temp3 + sdc * ((const float*)p)[c] + ct * amb_temp;
    c += xy;
    W += xy;
    E += xy;
    N += xy;
    S += xy;

    for (int k = 1; k < nz-1; ++k) {
        temp1 = temp2;
        temp2 = temp3;
        temp3 = ((const float*)tIn)[c+xy];
        ((float*)tOut)[c] = cc * temp2 + cw * ((const float*)tIn)[W] + ce * ((const float*)tIn)[E] + cs * ((const float*)tIn)[S]
            + cn * ((const float*)tIn)[N] + cb * temp1 + ct * temp3 + sdc * ((const float*)p)[c] + ct * amb_temp;
        c += xy;
        W += xy;
        E += xy;
        N += xy;
        S += xy;
    }
    temp1 = temp2;
    temp2 = temp3;
    ((float*)tOut)[c] = cc * temp2 + cw * ((const float*)tIn)[W] + ce * ((const float*)tIn)[E] + cs * ((const float*)tIn)[S]
        + cn * ((const float*)tIn)[N] + cb * temp1 + ct * temp3 + sdc * ((const float*)p)[c] + ct * amb_temp;
    return;
}
